import { STATUS_CONFIG } from '@/constants/status'

export function useStatus() {
  // indicator背景色和status文字颜色
  const getStatusColor = (status) => {
    return STATUS_CONFIG[status]?.color || STATUS_CONFIG.unknown.color
  }

  // status文字颜色样式对象
  // const getStatusTextStyle = (status) => ({
  //   color: STATUS_CONFIG[status]?.color || STATUS_CONFIG.unknown.color
  // })
  const getStatusTextStyle = (status) => {
    if (!status || status === 'ok') {
      return {} // ok 状态返回空对象，使用原有样式
    }
    return {
      color: STATUS_CONFIG[status]?.color || STATUS_CONFIG.unknown.color
    }
  }

  return {
    getStatusColor,
    getStatusTextStyle,
    statusConfig: STATUS_CONFIG // 导出配置用于图例
  }
}
